function solve(nums, queries) {
    const MOD = 10**9 + 7;
    const n = nums.length;
    const product = new Array(n).fill(1);

    for (const q of queries) {
        const li = q[0], ri = q[1], ki = q[2], vi = q[3];
        let idx = li;
        while (idx <= ri) {
            product[idx] = (product[idx] * vi) % MOD;
            idx += ki;
        }
    }

    let result = 0;
    for (let i = 0; i < n; i++) {
        result ^= (nums[i] * product[i]) % MOD;
    }

    return result;
}
